// =============================================
node.warn('NORM: Processing message from ' + (msg.topic || 'unknown'));

// INPUT NORMALIZATION
// Parse, validate structure, and normalize payload
// =============================================
let payload = msg.payload;

if (typeof payload === 'string') {
    try {
        payload = JSON.parse(payload);
    } catch(e) {
        msg.decision = 'REJECT';
        msg.rule_id = 'NORM-01';
        msg.reason = 'Invalid JSON payload: ' + e.message;
        return msg;
    }
}

msg.device_id = payload.device_id || null;
msg.token = payload.token || '';
msg.timestamp = payload.timestamp || null;
msg.temperature = payload.temperature;
msg.humidity = payload.humidity;
msg.decision = null;
msg.rule_id = null;
msg.reason = null;
msg.event_time = new Date().toISOString();
msg.token_masked = msg.token ? (msg.token.substring(0, 4) + '****') : 'none';
msg._original_ts = msg.timestamp;
msg._original_dev = msg.device_id;

return msg;

// =============================================
node.warn('AUTH-01: Checking token for device ' + (msg.device_id || 'unknown'));

// RULE-01: Token Authentication
// Verify device token matches configured secret
// =============================================
const EXPECTED_TOKEN = 'demo-secure-token-2024';

if (msg.decision === 'REJECT') return msg;

if (!msg.token || msg.token !== EXPECTED_TOKEN) {
    msg.decision = 'REJECT';
    msg.rule_id = 'RULE-01';
    msg.reason = 'Authentication failed: invalid or missing token';
    return msg;
}

return msg;

// =============================================
// RULE-02: Device Allowlist
// Only accept data from registered devices
// =============================================
const ALLOWED_DEVICES = ["sensor-001", "sensor-002"];

if (msg.decision === 'REJECT') return msg;

if (!msg.device_id || !ALLOWED_DEVICES.includes(msg.device_id)) {
    msg.decision = 'REJECT';
    msg.rule_id = 'RULE-02';
    msg.reason = 'Device not in allowlist: ' + (msg.device_id || 'null');
    return msg;
}

return msg;

// =============================================
// RULE-03: Schema Validation
// Verify required fields and data types
// =============================================
if (msg.decision === 'REJECT') return msg;

const required = ['device_id', 'token', 'timestamp', 'temperature', 'humidity'];
for (let i = 0; i < required.length; i++) {
    const field = required[i];
    if (msg[field] === null || msg[field] === undefined) {
        msg.decision = 'REJECT';
        msg.rule_id = 'RULE-03';
        msg.reason = 'Missing required field: ' + field;
        return msg;
    }
}

if (typeof msg.temperature !== 'number' || isNaN(msg.temperature)) {
    msg.decision = 'REJECT';
    msg.rule_id = 'RULE-03';
    msg.reason = 'Invalid type: temperature must be a number';
    return msg;
}

if (typeof msg.humidity !== 'number' || isNaN(msg.humidity)) {
    msg.decision = 'REJECT';
    msg.rule_id = 'RULE-03';
    msg.reason = 'Invalid type: humidity must be a number';
    return msg;
}

if (typeof msg.timestamp !== 'number' || isNaN(msg.timestamp)) {
    msg.decision = 'REJECT';
    msg.rule_id = 'RULE-03';
    msg.reason = 'Invalid type: timestamp must be a number';
    return msg;
}

msg.schema_valid = true;
return msg;

// =============================================
// RULE-04: Sensor Range Validation
// Verify sensor readings within acceptable thresholds
// Thresholds are lab defaults - adjustable per device type
// =============================================
const MAX_TEMP = 60;
const MIN_TEMP = -20;
const MAX_HUM = 100;
const MIN_HUM = 0;

if (msg.decision === 'REJECT') return msg;

if (msg.temperature < MIN_TEMP || msg.temperature > MAX_TEMP) {
    msg.decision = 'REJECT';
    msg.rule_id = 'RULE-04';
    msg.reason = 'Temperature ' + msg.temperature + 'C outside allowed range [' + MIN_TEMP + ', ' + MAX_TEMP + ']';
    return msg;
}

if (msg.humidity < MIN_HUM || msg.humidity > MAX_HUM) {
    msg.decision = 'REJECT';
    msg.rule_id = 'RULE-04';
    msg.reason = 'Humidity ' + msg.humidity + '% outside allowed range [' + MIN_HUM + ', ' + MAX_HUM + ']';
    return msg;
}

msg.range_valid = true;
return msg;

// =============================================
// RULE-05: Timestamp Freshness
// Reject data that is too old (default: 5 minutes)
// Lab accepts future timestamps (clock skew tolerance)
// Production should also enforce upper bound
// =============================================
const MAX_AGE_MS = 300000;

if (msg.decision === 'REJECT') return msg;

const now = Date.now();
const age = now - msg.timestamp;

if (age > MAX_AGE_MS) {
    msg.decision = 'REJECT';
    msg.rule_id = 'RULE-05';
    msg.reason = 'Timestamp too old: age=' + Math.round(age/1000) + 's exceeds max ' + Math.round(MAX_AGE_MS/1000) + 's';
    return msg;
}

msg.freshness_valid = true;
return msg;

// =============================================
// RULE-06: Replay / Duplicate Protection
// Detect duplicate payloads using timestamp+device_id
// Uses Node-RED flow context for state storage
// =============================================
if (msg.decision === 'REJECT') return msg;

let seen = flow.get('seen_timestamps') || {};
const key = msg.device_id + ':' + msg.timestamp;

if (seen[key]) {
    msg.decision = 'REJECT';
    msg.rule_id = 'RULE-06';
    msg.reason = 'Replay detected: duplicate timestamp ' + msg.timestamp + ' for device ' + msg.device_id;
    return msg;
}

seen[key] = msg.event_time;
const keys = Object.keys(seen);
if (keys.length > 1000) {
    const sorted = keys.sort(function(a, b) { return (seen[a] < seen[b] ? -1 : 1); });
    for (let i = 0; i < 100; i++) {
        delete seen[sorted[i]];
    }
}
flow.set('seen_timestamps', seen);

msg.replay_valid = true;
return msg;

// =============================================
node.warn('AUDIT: Decision=' + (msg.decision || 'null') + ' rule=' + (msg.rule_id || 'null'));

// AUDIT LOGGER
// Format structured audit log entry
// CRITICAL: Never log full token value
// =============================================
if (!msg.decision || msg.decision !== 'REJECT') {
    msg.decision = 'ACCEPT';
    msg.rule_id = 'PASS';
    msg.reason = 'All gateway checks passed';
}

const audit_entry = {
    event_time: msg.event_time,
    device_id: msg.device_id,
    token_hint: msg.token_masked,
    decision: msg.decision,
    rule_id: msg.rule_id,
    reason: msg.reason,
    temperature: msg.temperature,
    humidity: msg.humidity,
    timestamp_epoch: msg.timestamp,
    timestamp_age_ms: Date.now() - msg.timestamp
};

msg.audit_entry = audit_entry;
msg.payload = audit_entry;
msg.log_line = JSON.stringify(audit_entry);

return msg;
